<template>
    <aside class="aside">
        <div class="aside-user">
            <div class="avatar">
                <img :src="gravatar" alt="jawen">
            </div>
            <div class="profile">
                <h3 class="name">Jawen</h3>
                <p class="email">jawen.9@outlook.com</p>
            </div>
        </div>

        <div class="aside-nav">
            <div class="nav-list">
                <router-link class="item" to="/">
                    <i class="anticon icon-rocket1"></i>
                    <span>首页</span>
                </router-link>
                <router-link class="item" to="/gank">
                    <i class="anticon icon-gift"></i>
                    <span>福利</span>
                </router-link>
                <router-link class="item" to="/about">
                    <i class="anticon icon-warning"></i>
                    <span>关于</span>
                </router-link>
                <a class="item" @click="changeTheme">{{theme=='light'?'dark':'light'}}</a>
            </div>
        </div>
    </aside>
</template>
<script>
import { mapState } from 'vuex';
export default {
    data(){
        return{
            gravatar: ''
        }
    },
    computed: {
        ...mapState({
            theme: state => state.app.theme
        })
    },
    mounted(){
        this.getAvatar();
    },
    methods: {
        getAvatar(){
            this.axios.get(this.gankUrl+'/api/v2/random/category/Girl/type/Girl/count/1').then((res) => {
                if(res.data.data){
                    this.gravatar = res.data.data[0].url;
                }
            })
        },
        changeTheme() {
            if(this.theme == 'light') {
                this.$store.dispatch('ToggleTheme', 'dark');
                window.document.documentElement.setAttribute('data-theme', 'dark')
            } else {
                this.$store.dispatch('ToggleTheme', 'light');
                window.document.documentElement.setAttribute('data-theme', 'light')
            }
        }
    }
}
</script>
<style lang="scss" scoped>
.aside{
    display: block;
    overflow: auto;
    position: relative;
    width: 100%;
    height: 100%;
    margin: 0;
    opacity: 0;
    transform: scale(0.8, 0.8);
    transition: $mobile-aisde-transition;
    &.open {
        opacity: 1;
        transform: scale(1, 1);
        transition: $mobile-aisde-transition;
    }

    > .aside-user{
        width: 100%;
        display: flex;
        align-items: flex-start;
        flex-direction: column;
        padding: 1em;
        border-bottom: 1px solid darken($mobile-aside-bg, 5%);

        > .avatar{
            width: 35%;
            > img{
                max-width: 100%;
            }
        }

        > .profile{
            @include font_color($font-color-light);
            width: 100%;

            > .name{
                @include font_color($font-color-light);
                font-weight: bold;
                margin-bottom: 1rem;
            }
            > .email{
                @include font_color($font-color-light);
                margin: 0;
                overflow: hidden;
            }
        }
    }

    > .aside-nav{
        width: 100%;
        .nav-list{
            margin: 0;
            padding: 0;

            .item{
                border: none;
                display: block;
                width: 100%;
                height: 3em;
                line-height: 3em;
                padding: 0 1em;
                text-decoration: none;
                text-transform: uppercase;
                font-weight: 700;
                border-radius: 1px;
                @include font_color($font-color-light);
                margin-bottom: .5em;
                i{
                    width: 1em;
                    margin-right: 1em;
                    display: inline-block;
                    @include font_color($font-color-light);
                }
                span{
                    @include font_color($font-color-light);
                }
                &:hover {
                    color: $yellow;
                    @include bg_color($background-color-light);
                }
            }
        }
    }
}
</style>


