<template>
    <header class="header">
        <nav class="navbar">
            <div class="navbar-container">
                <div class="navbar-header">
                    <a href class="navbar-menu" @click.stop.prevent="toggleSidebar">
                        <i class="anticon" :class="mobileSidebar? 'icon-menu-unfold': 'icon-menu-fold'"></i>
                    </a>
                </div>
            </div>
        </nav>
    </header>
</template>
<script>
export default {
    computed: {
        mobileSidebar() {
            return this.$store.state.app.mobileSidebar
        }
    },
    watch: {
        '$route'(newVel, oldVel) {
            this.toggleSidebar(false)
        }
    },
    methods: {
        toggleSidebar(open) {
            this.$store.commit('TOGGLE_MOBILE_SIDEBAR', open)
        }
    }
}
</script>
<style lang="scss" scoped>
.header{
    position: fixed;
    top: 0;
    left: 0;
    width: 100%;
    height: $navbar-height;
    background: #0593d3;
    // @include bg_color($background-color-light);
    z-index: 10;

    .navbar{

        .navbar-container{
            height: $navbar-height;

            .navbar-header{
                height: $navbar-height;
                display: flex;
                position: relative;
                align-items: center;
                width: 100%;
                justify-content: space-between;

                .navbar-menu{
                    border: none;
                    display: inline-block;
                    height: $navbar-height;
                    width: 20%;
                    line-height: $navbar-height;
                    text-align: center;
                }
            }
        }
    }
}
</style>


